package graphql

import (
	"context"
	"fmt"

	"github.com/DocumentDrivenDX/ddx/internal/persona"
)

// Personas is the resolver for the personas field.
func (r *queryResolver) Personas(ctx context.Context, projectID *string) ([]*Persona, error) {
	loader := persona.NewPersonaLoader(r.personaProjectRoot(ctx, projectID))
	ps, err := loader.ListPersonas()
	if err != nil {
		return nil, fmt.Errorf("loading personas: %w", err)
	}
	gql := make([]*Persona, len(ps))
	for i, p := range ps {
		gql[i] = personaToGQL(p)
	}
	return gql, nil
}

// Persona is the resolver for the persona field.
func (r *queryResolver) Persona(ctx context.Context, name string, projectID *string) (*Persona, error) {
	loader := persona.NewPersonaLoader(r.personaProjectRoot(ctx, projectID))
	p, err := loader.LoadPersona(name)
	if err != nil {
		return nil, nil //nolint:nilerr // not-found is represented as null
	}
	return personaToGQL(p), nil
}

// personaProjectRoot resolves the working directory for persona loading.
// When a project ID is provided, it resolves via projectRoot; otherwise
// falls back to the server's working directory.
func (r *queryResolver) personaProjectRoot(ctx context.Context, projectID *string) string {
	if projectID != nil && *projectID != "" {
		return r.projectRoot(ctx, *projectID)
	}
	return r.workingDir(ctx)
}

// PersonaByRole is the resolver for the personaByRole field.
func (r *queryResolver) PersonaByRole(ctx context.Context, role string) (*Persona, error) {
	loader := persona.NewPersonaLoader(r.workingDir(ctx))
	ps, err := loader.FindByRole(role)
	if err != nil || len(ps) == 0 {
		return nil, nil
	}
	return personaToGQL(ps[0]), nil
}

// Coordinators is the resolver for the coordinators field.
func (r *queryResolver) Coordinators(ctx context.Context) ([]*CoordinatorMetricsEntry, error) {
	return r.State.GetCoordinatorsGraphQL(), nil
}

// CoordinatorMetricsByProject is the resolver for the coordinatorMetricsByProject field.
func (r *queryResolver) CoordinatorMetricsByProject(ctx context.Context, projectRoot string) (*CoordinatorMetrics, error) {
	return r.State.GetCoordinatorMetricsByProjectGraphQL(projectRoot), nil
}

// ─── helpers ──────────────────────────────────────────────────────────────────

func personaToGQL(p *persona.Persona) *Persona {
	source := p.Source
	if source == "" {
		source = persona.SourceLibrary
	}
	var filePath *string
	if p.FilePath != "" {
		fp := p.FilePath
		filePath = &fp
	}
	return &Persona{
		ID:          "persona-" + p.Name,
		Name:        p.Name,
		Roles:       p.Roles,
		Description: p.Description,
		Tags:        p.Tags,
		Content:     p.Content,
		Body:        p.Content,
		Source:      source,
		Bindings:    []*PersonaBinding{},
		FilePath:    filePath,
	}
}

package graphql

import (
	"context"
	"fmt"
	"net/url"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// providerModelsCacheTTL is how long cached provider model snapshots live
// before a query falls through to a live discovery call. The bead spec calls
// for a 60s TTL, surfaced as a package var so tests can lower it.
var providerModelsCacheTTL = 60 * time.Second

// providerModelsFetcher is the live discovery fetcher used by the cache. It
// is a package var so tests can replace it without standing up a real
// fizeau service. Production code uses fetchProviderModelsLive.
var providerModelsFetcher = fetchProviderModelsLive

type providerModelsCacheEntry struct {
	result    *ProviderModelsResult
	fetchedAt time.Time
}

var providerModelsCache = struct {
	sync.Mutex
	entries  map[string]providerModelsCacheEntry
	inFlight map[string]chan struct{}
}{
	entries:  make(map[string]providerModelsCacheEntry),
	inFlight: make(map[string]chan struct{}),
}

func providerModelsCacheKey(workDir, name string, kind ProviderKind) string {
	return workDir + "\x00" + strings.ToLower(strings.TrimSpace(name)) + "\x00" + string(kind)
}

// ProviderModels is the resolver for the providerModels query.
// Returns a cached snapshot when one is fresh (within TTL); otherwise issues
// a single coalesced live fetch (in-flight guard prevents duplicate concurrent
// discovery calls for the same key).
func (r *queryResolver) ProviderModels(ctx context.Context, name string, kind ProviderKind) (*ProviderModelsResult, error) {
	name = strings.TrimSpace(name)
	if name == "" {
		return nil, fmt.Errorf("name required")
	}
	if !kind.IsValid() {
		return nil, fmt.Errorf("invalid kind: %s", kind)
	}

	key := providerModelsCacheKey(r.workingDir(ctx), name, kind)

	if cached, ok := lookupProviderModelsCache(key); ok {
		// Serve cached copy with fromCache=true; do NOT alter fetchedAt.
		out := cloneProviderModelsResult(cached.result)
		out.FromCache = true
		return out, nil
	}

	res, err := loadProviderModels(ctx, r.workingDir(ctx), name, kind, key)
	if err != nil {
		return nil, err
	}
	out := cloneProviderModelsResult(res)
	out.FromCache = false
	return out, nil
}

// RefreshProviderModels is the resolver for the refreshProviderModels mutation.
// Always performs a live discovery, ignoring TTL, but still routes through the
// in-flight guard so concurrent refreshes for the same key are coalesced.
// Auth-gating is provided by the requireTrusted wrapper on the /graphql HTTP
// route (see cli/internal/server/server.go); this resolver runs only for
// trusted callers.
func (r *mutationResolver) RefreshProviderModels(ctx context.Context, name string, kind ProviderKind) (*ProviderModelsResult, error) {
	name = strings.TrimSpace(name)
	if name == "" {
		return nil, fmt.Errorf("name required")
	}
	if !kind.IsValid() {
		return nil, fmt.Errorf("invalid kind: %s", kind)
	}

	key := providerModelsCacheKey(r.workingDir(ctx), name, kind)
	res, err := refreshProviderModels(ctx, r.workingDir(ctx), name, kind, key)
	if err != nil {
		return nil, err
	}
	out := cloneProviderModelsResult(res)
	out.FromCache = false
	return out, nil
}

// lookupProviderModelsCache returns the cached entry when it is still fresh.
func lookupProviderModelsCache(key string) (providerModelsCacheEntry, bool) {
	providerModelsCache.Lock()
	defer providerModelsCache.Unlock()
	entry, ok := providerModelsCache.entries[key]
	if !ok || entry.result == nil {
		return providerModelsCacheEntry{}, false
	}
	if time.Since(entry.fetchedAt) > providerModelsCacheTTL {
		return providerModelsCacheEntry{}, false
	}
	return entry, true
}

// loadProviderModels returns a fresh result, performing a live discovery only
// when no other goroutine is already doing so. When an in-flight fetch exists
// for this key, the caller waits on its completion and then reads the cache.
func loadProviderModels(ctx context.Context, workDir, name string, kind ProviderKind, key string) (*ProviderModelsResult, error) {
	return doProviderModelsFetch(ctx, workDir, name, kind, key, false)
}

// refreshProviderModels forces a live discovery (no TTL check), still
// coalescing concurrent calls for the same key.
func refreshProviderModels(ctx context.Context, workDir, name string, kind ProviderKind, key string) (*ProviderModelsResult, error) {
	return doProviderModelsFetch(ctx, workDir, name, kind, key, true)
}

func doProviderModelsFetch(ctx context.Context, workDir, name string, kind ProviderKind, key string, force bool) (*ProviderModelsResult, error) {
	for {
		providerModelsCache.Lock()
		// If a fetch is in flight for this key, wait for it and re-evaluate.
		if ch, ok := providerModelsCache.inFlight[key]; ok {
			providerModelsCache.Unlock()
			select {
			case <-ch:
				if !force {
					if entry, ok := lookupProviderModelsCache(key); ok {
						return entry.result, nil
					}
				}
				// Fall through to retry — we either need a fresh fetch or the
				// previous attempt failed.
				continue
			case <-ctx.Done():
				return nil, ctx.Err()
			}
		}
		// We own the in-flight slot.
		ch := make(chan struct{})
		providerModelsCache.inFlight[key] = ch
		providerModelsCache.Unlock()

		result, err := providerModelsFetcher(ctx, workDir, name, kind)

		providerModelsCache.Lock()
		delete(providerModelsCache.inFlight, key)
		if err == nil && result != nil {
			providerModelsCache.entries[key] = providerModelsCacheEntry{
				result:    result,
				fetchedAt: time.Now().UTC(),
			}
		}
		providerModelsCache.Unlock()
		close(ch)

		if err != nil {
			return nil, err
		}
		return result, nil
	}
}

// fetchProviderModelsLive performs the live discovery via the agent service.
// For ENDPOINT kinds it filters by provider name; for HARNESS kinds it filters
// by harness name. The returned baseURL is sanitized (credentials, query, and
// fragment stripped) for ts-net display safety; harness rows return "".
func fetchProviderModelsLive(ctx context.Context, workDir, name string, kind ProviderKind) (*ProviderModelsResult, error) {
	svc, err := agent.NewServiceFromWorkDir(workDir)
	if err != nil {
		return nil, fmt.Errorf("agent service: %w", err)
	}

	filter := agentlib.ModelFilter{}
	switch kind {
	case ProviderKindEndpoint:
		filter.Provider = name
	case ProviderKindHarness:
		filter.Harness = name
	default:
		return nil, fmt.Errorf("invalid kind: %s", kind)
	}

	models, err := svc.ListModels(ctx, filter)
	if err != nil {
		return nil, fmt.Errorf("list models: %w", err)
	}

	baseURL := ""
	if kind == ProviderKindEndpoint {
		// Pick up the provider's base URL from ListProviders, fall back to
		// the first model's recorded EndpointBaseURL when discovery returned
		// it.
		if providers, perr := svc.ListProviders(ctx); perr == nil {
			for _, p := range providers {
				if strings.EqualFold(p.Name, name) {
					baseURL = sanitizeBaseURL(p.BaseURL)
					break
				}
			}
		}
		if baseURL == "" {
			for _, m := range models {
				if m.EndpointBaseURL != "" {
					baseURL = sanitizeBaseURL(m.EndpointBaseURL)
					break
				}
			}
		}
	}

	entries := make([]*ProviderModelEntry, 0, len(models))
	for _, m := range models {
		entry := &ProviderModelEntry{
			ID:        m.ID,
			Available: m.Available,
		}
		if m.ContextLength > 0 {
			cl := m.ContextLength
			entry.ContextLength = &cl
		}
		entries = append(entries, entry)
	}

	return &ProviderModelsResult{
		Name:      name,
		Kind:      kind,
		Models:    entries,
		BaseURL:   baseURL,
		FetchedAt: time.Now().UTC().Format(time.RFC3339),
		FromCache: false,
	}, nil
}

// sanitizeBaseURL returns a base URL safe to surface over a ts-net trusted
// channel: credentials, query string, and fragment are dropped, the scheme
// and host are preserved, and any path is kept verbatim. Inputs that fail to
// parse, or lack a host, return "" — never the original raw string — so a
// malformed config cannot leak credentials downstream.
func sanitizeBaseURL(raw string) string {
	raw = strings.TrimSpace(raw)
	if raw == "" {
		return ""
	}
	u, err := url.Parse(raw)
	if err != nil {
		return ""
	}
	if u.Scheme == "" || u.Host == "" {
		return ""
	}
	clean := &url.URL{
		Scheme: u.Scheme,
		Host:   u.Host,
		Path:   u.Path,
	}
	return clean.String()
}

// cloneProviderModelsResult deep-copies a result so cached entries are not
// mutated when callers flip FromCache or a future field.
func cloneProviderModelsResult(in *ProviderModelsResult) *ProviderModelsResult {
	if in == nil {
		return nil
	}
	out := *in
	if in.Models != nil {
		out.Models = make([]*ProviderModelEntry, 0, len(in.Models))
		for _, m := range in.Models {
			if m == nil {
				continue
			}
			mc := *m
			if m.ContextLength != nil {
				v := *m.ContextLength
				mc.ContextLength = &v
			}
			out.Models = append(out.Models, &mc)
		}
	}
	return &out
}

package graphql

import (
	"context"
	"fmt"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	agentlib "github.com/DocumentDrivenDX/fizeau"
)

var providerStatusCache = struct {
	sync.Mutex
	rows     map[string][]*ProviderStatus
	inFlight map[string]bool
}{
	rows:     make(map[string][]*ProviderStatus),
	inFlight: make(map[string]bool),
}

// harnessRateLimitCache holds the most recently observed rate-limit signal per
// harness name. The server invocation path (or tests) populates it via
// RecordHarnessRateLimit; quotaFromHarnessInfo reads it when the upstream
// HarnessInfo.Quota does not carry token-level ceilings.
var harnessRateLimitCache = struct {
	sync.RWMutex
	byName map[string]agent.RateLimitSignal
}{byName: make(map[string]agent.RateLimitSignal)}

// LookupHarnessRateLimit returns the last-observed signal for a harness, or
// ok=false if none has been recorded.
func LookupHarnessRateLimit(name string) (agent.RateLimitSignal, bool) {
	harnessRateLimitCache.RLock()
	defer harnessRateLimitCache.RUnlock()
	sig, ok := harnessRateLimitCache.byName[name]
	return sig, ok
}

// ProviderStatuses is the resolver for the providerStatuses field.
// It mirrors the output of `ddx agent providers`, annotating each row with
// kind=ENDPOINT, a lastCheckedAt timestamp, and rolling usage derived from
// the sessions index. Quota is populated when the upstream ProviderInfo
// exposes token-level quota headers; null otherwise (FEAT-014 no-fabrication).
func (r *queryResolver) ProviderStatuses(ctx context.Context) ([]*ProviderStatus, error) {
	now := time.Now().UTC()
	entries := r.sessionIndexEntries(ctx)

	if rows := cachedProviderRows(r.workingDir(ctx)); len(rows) > 0 {
		refreshProviderStatuses(r.workingDir(ctx))
		return providerRowsWithUsage(rows, entries, now), nil
	}

	if snapshots, ok, err := agent.ConfiguredProviderSnapshots(r.workingDir(ctx)); err == nil && ok {
		rows := providerStatusesFromInfos(snapshots, entries, now)
		storeProviderRows(r.workingDir(ctx), rows)
		refreshProviderStatuses(r.workingDir(ctx))
		return rows, nil
	} else if err != nil {
		return nil, fmt.Errorf("loading provider snapshots: %w", err)
	}

	// Legacy/global provider config fallback. Bound the synchronous path so the
	// UI can still first-paint harness rows even if provider probing is slow.
	probeCtx, cancel := context.WithTimeout(ctx, 500*time.Millisecond)
	defer cancel()
	providers, err := liveProviderInfos(probeCtx, r.workingDir(ctx))
	if err != nil {
		refreshProviderStatuses(r.workingDir(ctx))
		return []*ProviderStatus{}, nil
	}
	rows := providerStatusesFromInfos(providers, entries, now)
	storeProviderRows(r.workingDir(ctx), rows)
	return rows, nil
}

// HarnessStatuses is the resolver for the harnessStatuses field.
// It returns one row per subprocess harness (kind=HARNESS). Reachability is
// taken from HarnessInfo.Available, rolling usage from the sessions index,
// and quota/auth/model data directly from the upstream HarnessInfo DTO.
func (r *queryResolver) HarnessStatuses(ctx context.Context) ([]*ProviderStatus, error) {
	svc, err := agentlib.New(agentlib.ServiceOptions{})
	if err != nil {
		return []*ProviderStatus{}, nil //nolint:nilerr
	}
	infos, err := svc.ListHarnesses(ctx)
	if err != nil {
		return nil, fmt.Errorf("listing harnesses: %w", err)
	}

	now := time.Now().UTC()
	entries := r.sessionIndexEntries(ctx)
	return harnessStatusesFromInfos(infos, entries, now), nil
}

// DefaultRouteStatus is the resolver for the defaultRouteStatus field.
func (r *queryResolver) DefaultRouteStatus(ctx context.Context) (*DefaultRouteStatus, error) {
	svc, err := agent.NewServiceFromWorkDir(r.workingDir(ctx))
	if err != nil {
		return nil, nil //nolint:nilerr
	}
	dec, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{})
	if err != nil {
		return &DefaultRouteStatus{}, nil //nolint:nilerr
	}
	result := &DefaultRouteStatus{ModelRef: dec.Model}
	if dec.Provider != "" {
		p := dec.Provider
		result.ResolvedProvider = &p
	}
	if dec.Model != "" {
		m := dec.Model
		result.ResolvedModel = &m
	}
	return result, nil
}

// ProviderTrend is the resolver for the providerTrend field.
// It aggregates the sessions index into time buckets for one provider/harness
// and computes a projected-run-out-in-hours callout from the last-24h slope.
func (r *queryResolver) ProviderTrend(ctx context.Context, name string, windowDays int) (*ProviderTrend, error) {
	name = strings.TrimSpace(name)
	if name == "" {
		return nil, fmt.Errorf("name required")
	}
	if windowDays != 7 && windowDays != 30 {
		return nil, fmt.Errorf("windowDays must be 7 or 30")
	}
	now := time.Now().UTC()
	entries := r.sessionIndexEntries(ctx)

	kind, detected := detectProviderOrHarness(ctx, r, name)
	bucketKind := agent.MatchProvider
	if kind == ProviderKindHarness {
		bucketKind = agent.MatchHarness
	}

	bucketSize := time.Hour
	if windowDays > 7 {
		bucketSize = 4 * time.Hour
	}
	buckets := agent.BucketUsage(entries, name, bucketKind, now, windowDays, bucketSize)
	series := make([]*ProviderTrendPoint, 0, len(buckets))
	for _, b := range buckets {
		series = append(series, &ProviderTrendPoint{
			BucketStart: b.Start.UTC().Format(time.RFC3339),
			Tokens:      b.Tokens,
			Requests:    b.Requests,
		})
	}

	trend := &ProviderTrend{
		Name:       name,
		Kind:       kind,
		WindowDays: windowDays,
		Series:     series,
	}

	if detected != nil {
		if ceiling := detected.ceilingTokens; ceiling > 0 {
			c := ceiling
			trend.CeilingTokens = &c
			remaining := detected.remaining
			if remaining < 0 {
				remaining = ceiling - sumTailTokens(buckets, 24)
			}
			if p := projectRunOutHours(buckets, float64(remaining)); p > 0 {
				trend.ProjectedRunOutHours = &p
			}
		}
	}

	return trend, nil
}

