124		if name == "" {
125			return nil, fmt.Errorf("name required")
126		}
127		if windowDays != 7 && windowDays != 30 {
128			return nil, fmt.Errorf("windowDays must be 7 or 30")
129		}
130		now := time.Now().UTC()
131		entries := r.sessionIndexEntries(ctx)
